SELECT count(*) FROM movie_info, title, kind_type, info_type, cast_info, movie_keyword, movie_companies, keyword, company_type WHERE movie_info.movie_id = title.id AND title.kind_id = kind_type.id AND movie_info.info_type_id = info_type.id AND cast_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_companies.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND movie_companies.company_type_id = company_type.id;